  Future<Map<String, dynamic>> _executeWithRetry(
    Future<http.Response> Function() request,
    String url,
    Duration timeout, {
    int maxRetries = _maxRetries,
  }) async {
    int attempt = 0;
    while (true) {
      attempt++;
      try {
        final response = await request().timeout(timeout);
        return _processResponse(response, url);
      } on TimeoutException {
        if (attempt >= maxRetries) {
          throw HttpServiceException(
            message: 'Request timed out after $maxRetries attempts',
            url: url,
          );
        }
        // Exponential backoff
        await Future.delayed(Duration(milliseconds: 500 * attempt));
      } on SocketException catch (e) {
        if (attempt >= maxRetries) {
          throw HttpServiceException(
            message: 'Network error: ${e.message}',
            url: url,
            originalError: e,
          );
        }
        await Future.delayed(Duration(milliseconds: 500 * attempt));
      } on HttpServiceException {
        rethrow;
      } on http.ClientException catch (e) {
        if (attempt >= maxRetries) {
          throw HttpServiceException(
            message: 'Client error: ${e.message}',
            url: url,
            originalError: e,
          );
        }
        await Future.delayed(Duration(milliseconds: 500 * attempt));
      } catch (e) {
        if (attempt >= maxRetries) {
          throw HttpServiceException(
            message: 'Unexpected error: $e',
            url: url,
            originalError: e,
          );
        }
        await Future.delayed(Duration(milliseconds: 500 * attempt));
      }
    }
  }

  Map<String, dynamic> _processResponse(http.Response response, String url) {
    final statusCode = response.statusCode;

    if (statusCode >= 200 && statusCode < 300) {
      if (response.body.isEmpty) {
        return {'status': 'success', 'statusCode': statusCode};
      }
      try {
        final decoded = jsonDecode(response.body);
        if (decoded is Map<String, dynamic>) {
          return decoded;
        }
        // Wrap non-map responses
        return {'data': decoded, 'statusCode': statusCode};
      } on FormatException {
        return {
          'rawBody': response.body,
          'statusCode': statusCode,
        };
      }
    }

    String errorMessage;
    switch (statusCode) {
      case 400:
        errorMessage = 'Bad request';
        break;
      case 401:
        errorMessage = 'Unauthorized - check authentication';
        break;
      case 403:
        errorMessage = 'Forbidden - insufficient permissions';
        break;
      case 404:
        errorMessage = 'Resource not found';
        break;
      case 408:
        errorMessage = 'Request timeout';
        break;
      case 429:
        errorMessage = 'Too many requests - rate limited';
        break;
      case 500:
        errorMessage = 'Internal server error';
        break;
      case 502:
        errorMessage = 'Bad gateway';
        break;
      case 503:
        errorMessage = 'Service unavailable';
        break;
      default:
        errorMessage = 'HTTP error';
    }

    // Try to extract error details from response body
    String? serverMessage;
    try {
      final errorBody = jsonDecode(response.body);
      if (errorBody is Map) {
        serverMessage = errorBody['message']?.toString() ??
            errorBody['error']?.toString() ??
            errorBody['detail']?.toString();
      }
    } catch (_) {
      serverMessage = response.body.isNotEmpty ? response.body : null;
    }

    throw HttpServiceException(
      message: serverMessage != null
          ? '$errorMessage: $serverMessage'
          : errorMessage,
      statusCode: statusCode,
      url: url,
    );
  }

