// ==================== Usage Example ====================

Future<void> main() async {
  final httpService = HttpService();

  // Configure cloud API auth
  httpService.setCloudAuthToken('your-cloud-api-token');

  // Register local IoT devices
  httpService.registerDevice(
    'living-room-light',
    const IoTDeviceConfig(
      ipAddress: '192.168.1.100',
      port: 80,
      authToken: 'device-token-123',
    ),
  );

  httpService.registerDevice(
    'thermostat',
    const IoTDeviceConfig(
      ipAddress: '192.168.1.101',
      port: 8080,
    ),
  );

  httpService.registerDevice(
    'garage-door',
    const IoTDeviceConfig(
      ipAddress: '192.168.1.102',
      port: 80,
    ),
  );

  try {
    // --- Cloud API calls (HTTPS) ---
    print('--- Cloud API ---');

    // Fetch device list from cloud
    final devices = await httpService.cloudGet('/api/v1/devices');
    print('Cloud devices: $devices');

    // Register a new device in cloud
    final newDevice = await httpService.cloudPost(
      '/api/v1/devices',
      body: {
        'name': 'Kitchen Sensor',
        'type': 'temperature',
        'location': 'kitchen',
      },
    );
    print('New device registered: $newDevice');

    // Update device settings in cloud
    final updated = await httpService.cloudPatch(
      '/api/v1/devices/123',
      body: {'name': 'Updated Kitchen Sensor'},
    );
    print('Updated device: $updated');

    // --- Local IoT Device calls (HTTP) ---
    print('\n--- Local IoT Devices ---');

    // Get light status
    final lightStatus = await httpService.deviceGet(
      'living-room-light',
      '/status',
    );
    print('Light status: $lightStatus');

    // Turn on the light
    final lightOn = await httpService.devicePost(
      'living-room-light',
      '/control',
      body: {'action': 'on', 'brightness': 80},
    );
    print('Light turned on: $lightOn');

    // Get thermostat reading
    final temp = await httpService.deviceGet(
      'thermostat',
      '/temperature',
    );
    print('Temperature: $temp');

    // Set thermostat
    final thermostatSet = await httpService.devicePut(
      'thermostat',
      '/settings',
      body: {'target_temp': 22.5, 'mode': 'auto'},
    );
    print('Thermostat set: $thermostatSet');

    // Send raw command to garage door
    final garageResponse = await httpService.deviceSendRaw(
      'garage-door',
      '/command',
      rawBody: 'OPEN',
      contentType: 'text/plain',
    );
    print('Garage response: $garageResponse');

    // --- Health Checks ---
    print('\n--- Health Checks ---');

    final cloudHealthy = await httpService.checkCloudHealth();
    print('Cloud API healthy: $cloudHealthy');

    final lightReachable = await httpService.pingDevice('living-room-light');
    print('Light reachable: $lightReachable');

    final thermostatReachable = await httpService.pingDevice('thermostat');
    print('Thermostat reachable: $thermostatReachable');

    // --- Device Discovery ---
    print('\n--- Device Discovery ---');

    final discovered = await httpService.discoverDevices(
      subnet: '192.168.1',
      port: 80,
      startRange: 100,
      endRange: 110,
      timeout: const Duration(seconds: 1),
      healthEndpoint: '/status',
    );
    print('Discovered ${discovered.length} devices:');
    for (final device in discovered) {
      print('  - ${device.baseUrl}');
    }
  } on HttpServiceException catch (e) {
    print('HTTP Service Error: $e');
    if (e.originalError != null) {
      print('Original error: ${e.originalError}');
    }
  } catch (e) {
    print('Unexpected error: $e');
  } finally {
    httpService.dispose();
  }
}